## イベントストアの設計

### イベントストアのインターフェース

```go
// domain/repository/event_store.go
package repository

import "example/domain/event"

type EventStore interface {
    Save(aggregateID string, events []event.Event, expectedVersion int) error
    // LoadFrom は afterVersion より後（排他的）のイベントを返します。
    // afterVersion=0 の場合はすべてのイベントを返します。
    LoadFrom(aggregateID string, afterVersion int) ([]event.Event, error)
}
```

`expectedVersion` は楽観的ロックに使います。同じ集約に対して並行して書き込みが発生した場合、バージョンの不一致でエラーにすることで、データの整合性を保ちます。

`Save` メソッドの `defer tx.Rollback()` は、コミット成功後に呼ばれた場合は何もしません。`database/sql` の仕様で、コミット済みトランザクションの Rollback は無視されます。

### PostgreSQL 実装

```go
// infrastructure/postgres/event_store.go
package postgres

import (
    "database/sql"
    "encoding/json"
    "fmt"
    "time"

    "example/domain/event"
    "example/domain/repository"
)

type eventStore struct {
    db *sql.DB
}

func NewEventStore(db *sql.DB) repository.EventStore {
    return &eventStore{db: db}
}

func (s *eventStore) Save(aggregateID string, events []event.Event, expectedVersion int) error {
    tx, err := s.db.Begin()
    if err != nil {
        return fmt.Errorf("トランザクション開始に失敗しました: %w", err)
    }
    defer tx.Rollback()

    // 楽観的ロック：現在のバージョンを確認
    var currentVersion int
    err = tx.QueryRow(
        "SELECT COALESCE(MAX(version), 0) FROM events WHERE aggregate_id = $1",
        aggregateID,
    ).Scan(&currentVersion)
    if err != nil {
        return fmt.Errorf("バージョン確認に失敗しました: %w", err)
    }
    if currentVersion != expectedVersion {
        return fmt.Errorf("楽観的ロックエラー: 期待バージョン %d, 現在バージョン %d", expectedVersion, currentVersion)
    }

    // イベントを順番に保存
    for i, e := range events {
        payload, err := json.Marshal(e)
        if err != nil {
            return fmt.Errorf("イベントのシリアライズに失敗しました: %w", err)
        }
        _, err = tx.Exec(
            `INSERT INTO events (aggregate_id, version, event_type, payload, occurred_at)
             VALUES ($1, $2, $3, $4, $5)`,
            aggregateID,
            expectedVersion+i+1,
            e.EventType(),
            payload,
            e.OccurredAt(),
        )
        if err != nil {
            return fmt.Errorf("イベントの保存に失敗しました: %w", err)
        }
    }
    return tx.Commit()
}

func (s *eventStore) LoadFrom(aggregateID string, afterVersion int) ([]event.Event, error) {
    rows, err := s.db.Query(
        `SELECT event_type, payload, occurred_at FROM events
         WHERE aggregate_id = $1 AND version > $2 ORDER BY version ASC`,
        aggregateID, afterVersion,
    )
    if err != nil {
        return nil, fmt.Errorf("イベントの読み込みに失敗しました: %w", err)
    }
    defer rows.Close()

    var events []event.Event
    for rows.Next() {
        var eventType string
        var payload []byte
        var occurredAt time.Time

        if err := rows.Scan(&eventType, &payload, &occurredAt); err != nil {
            return nil, fmt.Errorf("イベントのスキャンに失敗しました: %w", err)
        }

        e, err := deserializeEvent(eventType, payload)
        if err != nil {
            return nil, err
        }
        events = append(events, e)
    }
    return events, rows.Err()
}

func deserializeEvent(eventType string, payload []byte) (event.Event, error) {
    switch eventType {
    case "OrderCreated":
        var e event.OrderCreated
        if err := json.Unmarshal(payload, &e); err != nil {
            return nil, fmt.Errorf("OrderCreatedのデシリアライズに失敗しました: %w", err)
        }
        return e, nil
    case "OrderConfirmed":
        var e event.OrderConfirmed
        if err := json.Unmarshal(payload, &e); err != nil {
            return nil, fmt.Errorf("OrderConfirmedのデシリアライズに失敗しました: %w", err)
        }
        return e, nil
    case "OrderShipped":
        var e event.OrderShipped
        if err := json.Unmarshal(payload, &e); err != nil {
            return nil, fmt.Errorf("OrderShippedのデシリアライズに失敗しました: %w", err)
        }
        return e, nil
    case "OrderCancelled":
        var e event.OrderCancelled
        if err := json.Unmarshal(payload, &e); err != nil {
            return nil, fmt.Errorf("OrderCancelledのデシリアライズに失敗しました: %w", err)
        }
        return e, nil
    default:
        return nil, fmt.Errorf("未知のイベントタイプ: %s", eventType)
    }
}
```

テーブルスキーマは次のとおりです。

```sql
CREATE TABLE events (
    id           BIGSERIAL PRIMARY KEY,
    aggregate_id VARCHAR(255) NOT NULL,
    version      INT NOT NULL,
    event_type   VARCHAR(255) NOT NULL,
    payload      JSONB NOT NULL,
    occurred_at  TIMESTAMP WITH TIME ZONE NOT NULL,
    created_at   TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    UNIQUE (aggregate_id, version)
);

CREATE INDEX idx_events_aggregate_id ON events (aggregate_id);
```

`(aggregate_id, version)` のユニーク制約が、楽観的ロックのデータベースレベルでの保証になります。アプリケーション側の `SELECT` + バージョン比較は早期エラー検出を目的としたものです。最終的な整合性はこのユニーク制約が保証します。PostgreSQL のデフォルト分離レベル（Read Committed）では、`SELECT` と `INSERT` の間に別のトランザクションがコミットする可能性があります。その場合でもユニーク制約違反でエラーになるため、データの不整合は発生しません。

