## 集約のイベントソーシング実装

### イベントを蓄積する集約

集約はコマンドを受け取り、ビジネスルールを検証したうえでドメインイベントを生成します。

```go
// domain/model/order.go
package model

import (
    "encoding/json"
    "errors"
    "fmt"
    "time"

    "example/domain/event"
)

type OrderStatus string

const (
    OrderStatusDraft     OrderStatus = "draft"
    OrderStatusConfirmed OrderStatus = "confirmed"
    OrderStatusShipped   OrderStatus = "shipped"
    OrderStatusCancelled OrderStatus = "cancelled"
)

type Order struct {
    id             string
    customerID     string
    status         OrderStatus
    items          []OrderItem
    trackingNumber string
    version        int
    changes        []event.Event // 未保存のイベント
}

type OrderItem struct {
    ProductID string
    Quantity  int
    Price     int
}
```

### コマンドメソッドとイベント適用

集約のコマンドメソッドは、ビジネスルールを検証してからイベントを生成します。`apply` メソッドがイベントを状態に反映します。

```go
func NewOrder(id, customerID string, items []OrderItem) (*Order, error) {
    if len(items) == 0 {
        return nil, errors.New("注文には1つ以上の商品が必要です")
    }
    o := &Order{}
    o.raise(event.OrderCreated{
        Base: event.Base{
            Type:      "OrderCreated",
            Timestamp: time.Now(),
            AggID:     id,
        },
        CustomerID: customerID,
        Items:      toEventItems(items),
    })
    return o, nil
}

func (o *Order) Confirm() error {
    if o.status != OrderStatusDraft {
        return fmt.Errorf("確認できるのは下書き状態の注文のみです（現在: %s）", o.status)
    }
    now := time.Now()
    o.raise(event.OrderConfirmed{
        Base: event.Base{
            Type:      "OrderConfirmed",
            Timestamp: now,
            AggID:     o.id,
        },
        ConfirmedAt: now,
    })
    return nil
}

func (o *Order) Ship(trackingNumber string) error {
    if o.status != OrderStatusConfirmed {
        return fmt.Errorf("出荷できるのは確認済みの注文のみです（現在: %s）", o.status)
    }
    o.raise(event.OrderShipped{
        Base: event.Base{
            Type:      "OrderShipped",
            Timestamp: time.Now(),
            AggID:     o.id,
        },
        TrackingNumber: trackingNumber,
    })
    return nil
}

// Cancel は下書きまたは確認済みの注文をキャンセルします。
// 出荷前であればキャンセル可能とする設計です。
func (o *Order) Cancel(reason string) error {
    if o.status == OrderStatusShipped {
        return fmt.Errorf("出荷済みの注文はキャンセルできません")
    }
    if o.status == OrderStatusCancelled {
        return fmt.Errorf("すでにキャンセルされています")
    }
    o.raise(event.OrderCancelled{
        Base: event.Base{
            Type:      "OrderCancelled",
            Timestamp: time.Now(),
            AggID:     o.id,
        },
        Reason: reason,
    })
    return nil
}

// raise はイベントを生成し、状態に適用します。
func (o *Order) raise(e event.Event) {
    o.apply(e)
    o.changes = append(o.changes, e)
}

// apply はイベントを集約の状態に反映します。
func (o *Order) apply(e event.Event) {
    switch ev := e.(type) {
    case event.OrderCreated:
        o.id = ev.AggregateID()
        o.customerID = ev.CustomerID
        o.status = OrderStatusDraft
        o.items = fromEventItems(ev.Items)
    case event.OrderConfirmed:
        o.status = OrderStatusConfirmed
    case event.OrderShipped:
        o.status = OrderStatusShipped
        o.trackingNumber = ev.TrackingNumber
    case event.OrderCancelled:
        o.status = OrderStatusCancelled
    }
    o.version++
}

// UncommittedChanges は未保存のイベントを返します。
func (o *Order) UncommittedChanges() []event.Event {
    return o.changes
}

// ClearChanges は未保存のイベントをクリアします。
func (o *Order) ClearChanges() {
    o.changes = nil
}

func (o *Order) Version() int {
    return o.version
}

func (o *Order) ReplayFrom(events []event.Event) {
    for _, e := range events {
        o.apply(e)
    }
}

func toEventItems(items []OrderItem) []event.OrderItemDetail {
    result := make([]event.OrderItemDetail, len(items))
    for i, item := range items {
        result[i] = event.OrderItemDetail{
            ProductID: item.ProductID,
            Quantity:  item.Quantity,
            Price:     item.Price,
        }
    }
    return result
}

func fromEventItems(items []event.OrderItemDetail) []OrderItem {
    result := make([]OrderItem, len(items))
    for i, item := range items {
        result[i] = OrderItem{
            ProductID: item.ProductID,
            Quantity:  item.Quantity,
            Price:     item.Price,
        }
    }
    return result
}
```

この設計のポイントは、`raise`（コマンド実行時）と `apply`（リプレイ時）を分離していることです。リプレイ時にはバリデーションを通さず、`apply` だけを呼び出します。

また、Go ではイベントを値型（構造体の値）として `raise` に渡しています。値型はコピーされるため、生成後のイベントが外部から変更される心配がありません。イベントソーシングにおいてイベントの不変性は重要な性質であり、Go の値セマンティクスがこれを自然に保証します。

なお、本記事では簡略化のため `time.Now()` を直接使用しています。テスタビリティを考慮する場合はクロック関数を注入する設計（例：`type Clock func() time.Time`）を検討してください。イベントのタイムスタンプはリプレイで再現される値なので、テストでの再現性が重要です。

